#include <adf.h>
using namespace adf;
class my_graph : public graph {
public:
  port<input> in;
  port<output> out;
  kernel k;
  my_graph() {
    k = kernel::create(my_kernel);
    source(k) = "my_kernel.cpp";
    connect<window<128>>(in, k.in[0]);
    connect<stream>(k.out[0], out);
    runtime<ratio>(k) = 0.9;
  }
};

artifacts.kernel_cpp:
#include <adf.h>
void my_kernel(input_window_int32* in, output_window_int32* out) {
  for (int i = 0; i < 64; ++i) {
    window_writeincr(out, window_readincr(in) + 1);
  }
}
